(function(){
'use strict';
function isEndlessRun(){return !!(window.S&&S.run&&S.endless&&!S.rift?.active&&!S.over)}
function checkpointLayer(){return Math.max(0,(S?.endlessLayer||1)-1)}
function saveCheckpoint(){try{saveGame?.()}catch(e){console.warn('无尽检查点存档失败:',e.code,e.message)}}
function ensurePanel(){let el=document.getElementById('endlessCheckpoint');if(el)return el;el=document.createElement('section');el.id='endlessCheckpoint';el.className='overlay hidden';el.innerHTML='<div class="panel result"><h1 class="title">无尽检查点</h1><p id="endlessCheckpointText" class="sub"></p><div class="choice"><h2>继续还是结算？</h2><p>每完成 10 层可以安全结束一次，立即结算本次无尽奖励；也可以继续挑战下一段。</p></div><p class="sub"><button id="endlessCheckpointEnd" class="startBtn" type="button">结束并结算</button><button id="endlessCheckpointContinue" class="ghostBtn" type="button">继续挑战</button></p></div>';document.querySelector('.game')?.appendChild(el);document.getElementById('endlessCheckpointEnd').onclick=()=>{el.classList.add('hidden');if(!isEndlessRun())return;S._endlessCheckpointPending=false;S.paused=false;end(true)};document.getElementById('endlessCheckpointContinue').onclick=()=>{el.classList.add('hidden');if(!isEndlessRun())return;S._endlessCheckpointPending=false;S.paused=false;showNotice(`继续无尽第 ${S.endlessLayer} 层挑战`);saveCheckpoint()};return el}
function maybeShowCheckpoint(){if(!isEndlessRun()||!S._endlessCheckpointPending)return;if(!document.getElementById('artifactChoice')?.classList.contains('hidden'))return;let done=S._endlessCheckpointLayer||checkpointLayer();let el=ensurePanel(),txt=document.getElementById('endlessCheckpointText');if(txt)txt.textContent=`已完成无尽第 ${done} 层，当前抵达第 ${S.endlessLayer} 层。`;S.paused=true;el.classList.remove('hidden');saveCheckpoint()}
function markCheckpointIfNeeded(beforeLayer){if(!isEndlessRun())return;let done=beforeLayer||checkpointLayer();if(done>0&&done%10===0&&S._endlessLastCheckpoint!==done){S._endlessLastCheckpoint=done;S._endlessCheckpointLayer=done;S._endlessCheckpointPending=true;showNotice(`无尽第 ${done} 层完成：可选择结束结算或继续挑战`);maybeShowCheckpoint()}}
function patchDeaths(){let base=window.deaths;if(typeof base!=='function'||base._endlessCheckpoint)return;window.deaths=function(){let before=isEndlessRun()?S.endlessLayer:0;base();if(isEndlessRun()&&S.endlessLayer!==before)markCheckpointIfNeeded(S.endlessLayer-1)};window.deaths._endlessCheckpoint=true}
function patchReward(name){let base=window[name];if(typeof base!=='function'||base._endlessCheckpoint)return;window[name]=function(){let r=base.apply(this,arguments);setTimeout(maybeShowCheckpoint,0);return r};window[name]._endlessCheckpoint=true}
function patchAll(){patchDeaths();patchReward('takeArtifactReward');patchReward('evolveSkill');console.info('无尽检查点已启用：每 10 层可结束或继续')}
patchAll();
})();
